class ListNode<T> {
  T value;
  ListNode<T>? next;
  ListNode(this.value, [this.next]);
}

class LinkedList<T> {
  ListNode<T>? head;
  int _length = 0;
  int get length => _length;
  bool get isEmpty => head == null;

  // O(1) — prepend
  void prepend(T value) {
    head = ListNode(value, head);
    _length++;
  }

  // O(n) — append
  void append(T value) {
    if (head == null) { prepend(value); return; }
    var cur = head!;
    while (cur.next != null) cur = cur.next!;
    cur.next = ListNode(value);
    _length++;
  }

  // O(1) — remove head
  T? removeFirst() {
    if (head == null) return null;
    final val = head!.value;
    head = head!.next;
    _length--;
    return val;
  }

  // O(n) — remove by value
  bool remove(T value) {
    if (head == null) return false;
    if (head!.value == value) { head = head!.next; _length--; return true; }
    var cur = head!;
    while (cur.next != null) {
      if (cur.next!.value == value) {
        cur.next = cur.next!.next;
        _length--;
        return true;
      }
      cur = cur.next!;
    }
    return false;
  }

  // O(n) — reverse in-place
  void reverse() {
    ListNode<T>? prev, cur = head;
    while (cur != null) {
      final next = cur.next;
      cur.next = prev;
      prev = cur;
      cur = next;
    }
    head = prev;
  }

  List<T> toList() {
    final result = <T>[];
    var cur = head;
    while (cur != null) { result.add(cur.value); cur = cur.next; }
    return result;
  }
}

